**4. DELETE - Remove Post**

```js
import { doc, getDoc, deleteDoc } from 'firebase/firestore';

export async function deletePost(postId, userId, userRole) {
  // 1. Get post
  const postRef = doc(db, 'posts', postId);
  const postSnap = await getDoc(postRef);

  if (!postSnap.exists()) {
    throw new Error('Post not found');
  }

  const postData = postSnap.data();

  // 2. Check authorization (owner or admin)
  const isOwner = postData.authorId === userId;
  const isAdmin = userRole === 'admin';

  if (!isOwner && !isAdmin) {
    throw new Error('Unauthorized - You can only delete your own posts');
  }

  // 3. Delete from Firestore
  await deleteDoc(postRef);

  // 4. Optional: Delete associated data (comments, likes)
  await deletePostComments(postId);

  revalidatePath('/blog');
  revalidatePath('/dashboard');
  redirect('/dashboard');
}

// Helper: Delete all comments for a post
async function deletePostComments(postId) {
  const commentsRef = collection(db, 'comments');
  const q = query(commentsRef, where('postId', '==', postId));
  const snapshot = await getDocs(q);

  const deletePromises = snapshot.docs.map(doc => deleteDoc(doc.ref));
  await Promise.all(deletePromises);
}
```

