**What are Firebase Security Rules?**

Firebase Security Rules determine **who can read or write** your data. They run on Google's servers and provide **server-side validation** — clients cannot bypass them.

**Key Concepts:**
- `request.auth` → Information about authenticated user
- `request.auth.uid` → User's unique ID
- `resource.data` → Existing document data
- `request.resource.data` → Incoming document data (for writes)
- `get()` → Fetch another document
- `exists()` → Check if document exists

---

**Complete Security Rules:**

```typescript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // ============================================
    // HELPER FUNCTIONS
    // ============================================

    function isSignedIn() {
      return request.auth != null;
    }

    function getUserData() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data;
    }

    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    function isAdmin() {
      return isSignedIn() && getUserData().role == 'admin';
    }

    function isOwnerOrAdmin(userId) {
      return isOwner(userId) || isAdmin();
    }

    // ============================================
    // USERS COLLECTION
    // ============================================

    match /users/{userId} {
      // Anyone can read user profiles
      allow read: if true;

      // Only create your own user document during registration
      allow create: if isSignedIn() 
                    && request.auth.uid == userId
                    && request.resource.data.role == 'user';  // Prevent self-promotion to admin

      // Only update your own profile (or admin can update anyone)
      allow update: if isOwnerOrAdmin(userId)
                    && (!request.resource.data.diff(resource.data).affectedKeys().hasAny(['role'])  // Prevent role change
                        || isAdmin());  // Unless admin

      // Only admins can delete users
      allow delete: if isAdmin();
    }

    // ============================================
    // POSTS COLLECTION
    // ============================================

    match /posts/{postId} {
      // Anyone can read published posts
      allow read: if resource.data.published == true;

      // Authors can read their own unpublished posts
      allow read: if isSignedIn() && resource.data.authorId == request.auth.uid;

      // Admins can read all posts
      allow read: if isAdmin();

      // Only authenticated users can create posts
      allow create: if isSignedIn()
                    && request.resource.data.authorId == request.auth.uid  // Must be post author
                    && request.resource.data.keys().hasAll(['title', 'slug', 'content', 'authorId', 'published'])  // Required fields
                    && request.resource.data.title is string
                    && request.resource.data.title.size() >= 3
                    && request.resource.data.title.size() <= 200
                    && request.resource.data.content is string
                    && request.resource.data.content.size() >= 10
                    && request.resource.data.authorId is string
                    && request.resource.data.published is bool
                    && request.resource.data.views == 0;  // Views must start at 0

      // Authors can update their own posts (or admins can update any)
      allow update: if isSignedIn()
                    && (resource.data.authorId == request.auth.uid || isAdmin())
                    && request.resource.data.authorId == resource.data.authorId;  // Cannot change author

      // Authors can delete their own posts (or admins can delete any)
      allow delete: if isSignedIn()
                    && (resource.data.authorId == request.auth.uid || isAdmin());
    }

    // ============================================
    // COMMENTS COLLECTION
    // ============================================

    match /comments/{commentId} {
      // Anyone can read comments
      allow read: if true;

      // Only authenticated users can create comments
      allow create: if isSignedIn()
                    && request.resource.data.authorId == request.auth.uid  // Must be comment author
                    && request.resource.data.keys().hasAll(['content', 'authorId', 'postId'])  // Required fields
                    && request.resource.data.content is string
                    && request.resource.data.content.size() >= 1
                    && request.resource.data.content.size() <= 1000
                    && exists(/databases/$(database)/documents/posts/$(request.resource.data.postId));  // Post must exist

      // Authors can update their own comments (or admins)
      allow update: if isOwnerOrAdmin(resource.data.authorId)
                    && request.resource.data.authorId == resource.data.authorId  // Cannot change author
                    && request.resource.data.postId == resource.data.postId;     // Cannot change post

      // Authors can delete their own comments, or admins can delete any
      allow delete: if isOwnerOrAdmin(resource.data.authorId);
    }

    // ============================================
    // CATEGORIES COLLECTION
    // ============================================

    match /categories/{categoryId} {
      // Anyone can read categories
      allow read: if true;

      // Only admins can create, update, or delete categories
      allow create, update, delete: if isAdmin();
    }

    // ============================================
    // TAGS COLLECTION
    // ============================================

    match /tags/{tagId} {
      // Anyone can read tags
      allow read: if true;

      // Only admins can create, update, or delete tags
      allow create, update, delete: if isAdmin();
    }
  }
}
```

